import{_ as o,o as c,c as a,ai as d,ap as t}from"./chunks/framework.C-hzIKVg.js";const f=JSON.parse('{"title":"USBメモリの準備","description":"","frontmatter":{},"headers":[],"relativePath":"prepare/usb-setup.md","filePath":"prepare/usb-setup.md"}'),s={name:"prepare/usb-setup.md"};function r(p,e,u,i,l,n){return c(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="usbメモリの準備" tabindex="-1">USBメモリの準備 <a class="header-anchor" href="#usbメモリの準備" aria-label="Permalink to “USBメモリの準備”">​</a></h1><p>USBメモリをリセットし、リソグラフで利用できるようにします。</p><h2 id="fat32へのフォーマット" tabindex="-1">FAT32へのフォーマット <a class="header-anchor" href="#fat32へのフォーマット" aria-label="Permalink to “FAT32へのフォーマット”">​</a></h2><p>USBメモリをPCに接続します。</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>USBメモリの中身はすべて消去されるので、必要なデータが入っていないか確認してください。 また、手順を誤ると、PCの他のドライブを消去してしまう可能性があるので、十分に注意してください。</p></div><p>前の手順でダウンロードフォルダにダウンロードした、<code>rufus-0.00p.exe</code>をダブルクリックして、Rufusを起動してください。<br> 初回は<code>アップデートの自動確認機能</code>についてのアラートが表示されるので、<code>いいえ</code>をクリックしてください。</p><p>Rufusが起動したら、<code>デバイス</code>で利用するUSBメモリを選択してください。<br> 次に、<code>ブートの選択</code>から、<code>非ブート用</code>を選択してください。<br> 次に、<code>ファイルシステム</code>から、<code>FAT32</code>もしくは<code>Large FAT32</code>を選択してください。 <img src="'+t+'" alt="Rufus"></p><p>特に<code>デバイス</code>に間違いがないことを確認して、<code>スタート</code>をクリックしてください。<br> アラートに従い<code>OK</code>をクリックして、フォーマットを開始してください。</p><p><code>状態</code>表示が再び<code>準備完了</code>になったら、<code>閉じる</code>をクリックしてRufusを終了してください。</p>',9)])])}const b=o(s,[["render",r]]);export{f as __pageData,b as default};
